import { useNavigate } from "react-router-dom";
import avatar from "../avatar.png";

function Welcome() {
  const navigate = useNavigate();

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        alignItems: "center",
        height: "100vh",
        background: "linear-gradient(135deg, #dbeafe, #f0fdf4)",
        fontFamily: "Arial",
        textAlign: "center",
      }}
    >
      <img
        src={avatar}
        alt="Therapist Avatar"
        style={{ width: "180px", marginBottom: "20px" }}
      />

      <h1 style={{ color: "#1e293b" }}>
        Welcome to Mental Health Chatbot
      </h1>

      <p style={{ color: "#475569", maxWidth: "400px" }}>
        Your safe, supportive space to talk, reflect, and heal.
      </p>

      <div style={{ marginTop: "25px" }}>
        <button
          onClick={() => navigate("/login")}
          style={{
            marginRight: "12px",
            padding: "12px 26px",
            borderRadius: "8px",
            border: "none",
            backgroundColor: "#2563eb",
            color: "white",
            fontSize: "16px",
            cursor: "pointer",
          }}
        >
          Login
        </button>

        <button
          onClick={() => navigate("/signup")}
          style={{
            padding: "12px 26px",
            borderRadius: "8px",
            border: "none",
            backgroundColor: "#16a34a",
            color: "white",
            fontSize: "16px",
            cursor: "pointer",
          }}
        >
          Sign Up
        </button>
      </div>
    </div>
  );
}

export default Welcome;
